@page "/apply/personal-info"
@rendermode InteractiveServer
@inject sv_066a45168a264cdd8cd46c583727993a.Services.ApplicationState AppState
@inject NavigationManager Nav

<PageTitle>Personal Info – Application</PageTitle>

<h1>Step 1: Personal Information</h1>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="AppState.PersonalInfo.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email Address</label>
    <input class="form-control" type="email" @bind="AppState.PersonalInfo.Email" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private void Next()
    {
        AppState.MarkStepCompleted(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject sv_066a45168a264cdd8cd46c583727993a.Services.ApplicationState AppState
@inject NavigationManager Nav

<PageTitle>Experience – Application</PageTitle>

<h1>Step 2: Experience</h1>

@for (int i = 0; i < AppState.Experience.Count; i++)
{
    var entry = AppState.Experience[i];
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="entry.Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Job Title</label>
            <input class="form-control" @bind="entry.Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="entry.Years" />
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add another</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private void AddEntry() => AppState.Experience.Add(new());

    private void Back() => Nav.NavigateTo("/apply/personal-info");

    private void Next()
    {
        AppState.MarkStepCompleted(2);
        Nav.NavigateTo("/apply/references");
    }
}

