using sv_066a45168a264cdd8cd46c583727993a.Models;

namespace sv_066a45168a264cdd8cd46c583727993a.Services;

/// <summary>
/// Scoped service that holds wizard data for a single user's circuit.
/// Persists across page navigations because enhanced navigation keeps the circuit alive.
/// </summary>
public class ApplicationState
{
    public PersonalInfo PersonalInfo { get; set; } = new();
    public List<ExperienceEntry> Experience { get; set; } = [new()];
    public List<ReferenceContact> References { get; set; } = [new()];

    // Track which steps the user has explicitly saved
    public HashSet<int> CompletedSteps { get; } = [];

    public event Action? OnChange;

    public void MarkStepCompleted(int step)
    {
        CompletedSteps.Add(step);
        OnChange?.Invoke();
    }
}

