﻿@inherits LayoutComponentBase
@inject NavigationManager Nav

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (IsWizardPage)
            {
                <nav class="wizard-progress">
                    @for (int i = 0; i < steps.Length; i++)
                    {
                        var step = steps[i];
                        var stepNum = i + 1;
                        var isCurrent = string.Equals(CurrentPath, step.Path, StringComparison.OrdinalIgnoreCase);
                        var isCompleted = stepNum < CurrentStepNumber;
                        <a href="@step.Path"
                           class="wizard-step @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "")">
                            <span class="step-number">@stepNum</span>
                            <span class="step-label">@step.Label</span>
                        </a>
                        @if (stepNum < steps.Length)
                        {
                            <span class="step-connector @(isCompleted ? "completed" : "")"></span>
                        }
                    }
                </nav>
            }
            else
            {
                <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
            }
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

